// ── SAGE v2: LOAD CONTEXT + PIPELINE DATA ────────────────────
const fs     = require('fs');
const https  = require('https');
const input  = $input.first().json;
const body   = input.body || input;

const mode      = String(body.mode || body.type || body.newsletter || 'board').toLowerCase();
const milestone = String(body.milestone || '');
const source    = String(body.source || 'manual');

let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8').replace(/\uFEFF/g, '')); } catch(e) { ctx = {}; }

const entities    = ctx.entities || {};
const founder     = ctx.founder || {};
const tech        = ctx.technology || {};
const revenue     = ctx.revenue_targets || {};
const competitive = ctx.competitive_moat || {};

let irisReport = 'No Iris report available.';
try {
  const files = fs.readdirSync('/data/Aidan_Outputs/Iris/').filter(function(f){return f.endsWith('.txt');}).sort().reverse();
  if (files.length > 0) irisReport = fs.readFileSync('/data/Aidan_Outputs/Iris/' + files[0], 'utf8').substring(0, 2000);
} catch(e) {}

let scoutReport = 'No Scout report available.';
try {
  const files = fs.readdirSync('/data/Maryland_Grants/').filter(function(f){return f.endsWith('.txt');}).sort().reverse();
  if (files.length > 0) scoutReport = fs.readFileSync('/data/Maryland_Grants/' + files[0], 'utf8').substring(0, 2000);
} catch(e) {}

let jordanReport = 'No Jordan report available.';
try {
  const files = fs.readdirSync('/data/Aidan_Outputs/Jordan/').filter(function(f){return f.startsWith('Pipeline_') && f.endsWith('.txt');}).sort().reverse();
  if (files.length > 0) jordanReport = fs.readFileSync('/data/Aidan_Outputs/Jordan/' + files[0], 'utf8').substring(0, 2000);
} catch(e) {}

const SUPABASE_URL = ($env.SUPABASE_URL || '').replace('https://','').replace('http://','');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || '';
let pipelineData = [];
let pipelineSummary = 'Pipeline data unavailable.';
try {
  const result = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: SUPABASE_URL, port: 443,
      path: '/rest/v1/pipeline?select=title,entity,status,fit_score,award_value,issuing_body,last_contact_date,loi_sent&order=last_activity_at.desc&limit=20',
      method: 'GET',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    }, (res) => { let d=''; res.on('data',c=>d+=c); res.on('end',()=>resolve({status:res.statusCode,body:d})); });
    req.on('error', reject);
    req.end();
  });
  if (result.status === 200) {
    pipelineData = JSON.parse(result.body) || [];
    const pursuing = pipelineData.filter(function(p){ return p.status === 'pursuing'; });
    const loiSent  = pipelineData.filter(function(p){ return p.loi_sent === true; });
    const won      = pipelineData.filter(function(p){ return p.status === 'won'; });
    pipelineSummary = 'Total pipeline: ' + pipelineData.length + ' opportunities\n' +
      'Actively pursuing: ' + pursuing.length + '\n' +
      'LOI/outreach sent: ' + loiSent.length + '\n' +
      'Won: ' + won.length + '\n\nActive opportunities:\n' +
      pursuing.map(function(p){
        return '* [' + p.entity + '] ' + p.title + (p.award_value ? ' | ' + p.award_value : '') + (p.fit_score ? ' | Fit: ' + p.fit_score + '%' : '');
      }).join('\n');
  }
} catch(e) { pipelineSummary = 'Pipeline query failed: ' + e.message; }

const activeDeadlines = (ctx.deadlines || []).filter(function(d) {
  const st = (d.status || '').toUpperCase();
  return st !== 'FILED' && st !== 'COMPLETE' && st !== 'EXEMPT';
});

const month = new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric', timeZone: 'America/New_York' });

return [{ json: {
  mode, milestone, source, month,
  ctx, entities, founder, tech, revenue, competitive,
  irisReport, scoutReport, jordanReport,
  pipelineData, pipelineSummary, activeDeadlines,
  timestamp: new Date().toISOString()
}}];

