// ── SAGE v2: SEND APPROVED NEWSLETTER ───────────────────────
// Triggered by: POST /webhook/sage-send with { mode: 'board'|'market'|'investor' }
// Queries contacts table for recipients by role
// Reads latest draft file for mode
// Sends via Gmail OAuth through n8n Gmail node
const https = require('https');
const fs    = require('fs');
const input = $input.first().json;
const body  = input.body || input;

const mode = String(body.mode || 'board').toLowerCase();
const SUPABASE_URL = ($env.SUPABASE_URL || '').replace('https://','').replace('http://','');
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || '';

// Map mode to contact role
const roleMap = { board: 'board_eaf', market: 'market_subscriber', investor: 'investor' };
const role = roleMap[mode] || 'board_eaf';

// Query contacts table for active recipients
let recipients = [];
try {
  const result = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: SUPABASE_URL, port: 443,
      path: '/rest/v1/contacts?role=eq.' + role + '&active=eq.true&newsletter_opt_in=eq.true&select=name,email',
      method: 'GET',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    }, (res) => { let d=''; res.on('data',c=>d+=c); res.on('end',()=>resolve({status:res.statusCode,body:d})); });
    req.on('error', reject);
    req.end();
  });
  if (result.status === 200) {
    const rows = JSON.parse(result.body) || [];
    recipients = rows.filter(function(r){ return r.email && r.email.trim() !== ''; });
  }
} catch(e) {
  throw new Error('Failed to query contacts: ' + e.message);
}

if (recipients.length === 0) {
  throw new Error('No active recipients found for mode: ' + mode + ' (role: ' + role + '). Add contacts to Supabase contacts table.');
}

// Find latest draft file for this mode
const dirMap = { board: 'Board_Newsletter', market: 'Market_Newsletter', investor: 'Investor_Brief' };
const prefix = dirMap[mode] || 'Board_Newsletter';
const sageDir = '/data/Aidan_Outputs/Sage/';
let draftContent = '';
let draftFile = '';
try {
  const files = fs.readdirSync(sageDir)
    .filter(function(f){ return f.startsWith(prefix) && f.endsWith('.txt'); })
    .sort().reverse();
  if (files.length === 0) throw new Error('No ' + prefix + ' draft found in ' + sageDir);
  draftFile = sageDir + files[0];
  draftContent = fs.readFileSync(draftFile, 'utf8');
} catch(e) {
  throw new Error('Could not load draft: ' + e.message);
}

// Subject line by mode
const month = new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric', timeZone: 'America/New_York' });
const subjectMap = {
  board:    'EAF Board Newsletter | ' + month,
  market:   'KAI-Netics Market Update | ' + month,
  investor: 'KAI-Netics Investor Brief | ' + month
};
const subject = subjectMap[mode] || 'KAI-Netics Update | ' + month;

