  '<p style="color:#8899aa;margin:3px 0 0;font-size:11px;">Kevin Alexander International LLC dba KAI-Netics</p>' +
  '</div>' +
  '<div style="background:#ffffff;padding:28px 28px 20px;border:1px solid #e0e0e0;">' +
  '<p style="margin:0 0 14px 0;font-size:14px;line-height:1.8;color:#222;">' + safeBody + '</p>' +
  '</div>' +
  '<div style="background:#f8f9fa;border:1px solid #e0e0e0;border-top:none;padding:16px 24px;border-radius:0 0 8px 8px;">' +
  '<p style="margin:0;font-size:12px;color:#555;">Kevin Alexander Smith | kas@kevin-llc.com | 443.257.6836</p>' +
  '<p style="margin:3px 0 0;font-size:11px;color:#777;">FAA Part 107 #5250157 | CISSP | PMP | MWVOB | Maryland</p>' +
  '</div></div>';

return [{ json: {
  mode, subject, htmlBody, draftContent, draftFile,
  recipients, recipientCount: recipients.length,
  toList: recipients.map(function(r){ return r.email; }).join(','),
  bcc: 'kas42869@gmail.com',
  month, sentAt: new Date().toISOString()
}}];

